/*! * Name : MountainB * Version : 2.50 * Variant : Surface * License : MIT * Description : Blogger template for personal blog and other uses. * Author : Dimas A. Gómez * Author URL : https://github.com/dimas-a-gomez * Sopport : https://discord.gg/M9q2YCxwJg * Changelog : .link * Donate : https://ko-fi.com/dimasagomez * Copyright : 2026 MountainB - Engines MicroTecN Co. *//*!
Admin ===================== [boolean] Enable the button to edit widgets <Variable name="a.layoutEdit" description="a.layoutEdit" type="string" value="false"/>
General ===================== [image] Url of default avatar. <Variable name="c.avatar" description="c.avatar" type="string" value="https://lh3.googleusercontent.com/a/default-user"/>
[image] HD Favicon URL. <Variable name="c.favicon" description="c.favicon" type="string"/>
[string] Formspree.io form ID. <Variable name="c.formspree" description="c.formspree" type="string"/>
[string] Image parameters: https://zkreations.com/image-params <Variable name="c.imageParams" description="c.imageParams" type="string" value="rw-l80-e30"/>
[image] Url of default Open Graph image. <Variable name="c.ogImage" description="c.ogImage" type="string"/>
[string] Footer Description <Variable name="c.footerDescription" description="c.footerDescription" type="string" value="MountainB Club, un espacio de reflexión y aprendizaje."/>
Translatable strings ===================== <Variable name="t.delete" description="t.delete" type="string" value="Delete"/> <Variable name="t.reply" description="t.reply" type="string" value="Reply"/>
Customization ===================== [!] Mandatory variable to enable dynamic layout <Variable name="keycolor" description="keycolor" type="color" value="#2196f3" default="#2196f3"/>
<Group description="Backgrounds"> <Variable name="background" description="Body Background" type="color" default="#FFF" value="#FFF"/> <Variable name="surface" description="Surface Background" type="color" default="#F0F0F0" value="#F0F0F0"/> <Variable name="d.background" description="Dark Body Background" type="color" default="#141414" value="#141414"/> <Variable name="d.surface" description="Dark Surface Background" type="color" default="#262626" value="#262626"/> </Group> <Group description="Colors"> <Variable name="primary" description="Primary Color" type="color" default="#006FFF" value="#006FFF"/> <Variable name="d.primary" description="Dark Primary Color" type="color" default="#0056CC" value="#0056CC"/> <Variable name="m.t.color" description="Main Text Color" type="color" default="#2D3436" value="#2D3436"/> <Variable name="s.t.color" description="Secondary Text Color" type="color" default="#333333" value="#333333"/> <Variable name="d.m.t.color" description="Dark Main Text Color" type="color" default="#FFF" value="#FFF"/> <Variable name="d.s.t.color" description="Dark Secondary Text Color" type="color" default="#F0F0F0" value="#F0F0F0"/> <Variable name="s.m.t.color" description="Secondary Main Text Color" type="color" default="#565656" value="#565656"/> <Variable name="i.color" description="Icon Color" type="color" default="#111" value="#111"/> </Group> <Group description="Fonts"> <!-- Fuente para los Títulos (Gloock) --> <Variable name="font.title" description="Title font" type="font" default="normal 400 1rem 'Gloock', serif" value="normal 400 1rem 'Gloock', serif"/>
<!-- Fuente para el Cuerpo / Textos (Inter estándar) --> <Variable name="font.text" description="Text font" type="font" default="normal 400 1rem 'Inter', sans-serif" value="normal 400 1rem 'Inter', sans-serif"/> </Group> <Group description="Fuentes personalizadas" selector="SELECTOR_CSS"> <Variable name="font.headings" description="Fuente de Títulos" type="font" default="normal 400 2.5rem 'Gloock', serif" value="normal 400 2.5rem 'Gloock', serif"/> <Variable name="font.body" description="Fuente de Cuerpo" type="font" default="normal 400 1rem 'Inter', sans-serif" value="normal 400 1rem 'Inter', sans-serif"/> </Group> <Variable name="posts.text.color" description="posts.text.color" hideEditor="true" type="color" value="#666" default="#666"/> <Variable name="posts.link.color" description="posts.link.color" type="string" value="#666"/> <Variable name="posts.text.font" description="posts.text.font" type="string" value="15px Roboto"/> <Variable name="posts.background.color" description="posts.background.color" type="string" value="transparent"/> <Variable name="posts.title.color" description="posts.title.color" type="string" value="false"/> <Variable name="body.link.color" description="body.link.color" type="string" value="false"/> <Variable name="body.text.font" description="body.text.font" type="string" value="false"/>
Skin CSS variables =====================*/ :root { /* Fonts Group */ --font-title: $(font.title); --font-title-family: $(font.title.family); --font-text: $(font.text); --font-text-family: $(font.text.family);
